// Some portions generated by Codex

package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.repository.util.RDFInserter;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSparsePrefixCostTest {

	private static final String PREFIX = """
			PREFIX schema: <https://schema.org/>
			""";

	private static final List<String> SPARSE_DEEP_PATH_PREFIXES = List.of(
			"?person a schema:Person .",
			"?person schema:memberOf ?org .",
			"?org schema:department ?department .",
			"?department schema:makesOffer ?offer .",
			"?offer schema:itemOffered ?work .",
			"?work schema:about ?topic .",
			"?topic schema:mainEntityOfPage ?page .",
			"?person schema:position ?personPosition .");

	@Test
	void sparseDeepPathPrefixesHaveActualCountsAndOptimizedPlannedCosts(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig storeConfig = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, storeConfig);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSparseData(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				for (int prefixLength = 1; prefixLength <= SPARSE_DEEP_PATH_PREFIXES.size(); prefixLength++) {
					String query = sparsePrefixQuery(prefixLength);
					long actualRows = countRows(connection, query);
					assertTrue(actualRows > 0L, "Expected prefix " + prefixLength + " to produce rows");

					Explanation explanation = connection.prepareTupleQuery(query)
							.explain(Explanation.Level.Optimized);
					TupleExpr root = (TupleExpr) explanation.tupleExpr();

					double plannedCostWorkRows = root
							.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS);
					assertTrue(Double.isFinite(plannedCostWorkRows) && plannedCostWorkRows >= 0.0d,
							"Expected finite root plannedCostWorkRows for prefix " + prefixLength
									+ ", actualRows=" + actualRows + "\n" + explanation);

					double plannedCardinalityRows = root
							.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS);
					assertTrue(Double.isFinite(plannedCardinalityRows) && plannedCardinalityRows >= 0.0d,
							"Expected finite root plannedCardinalityRows for prefix " + prefixLength
									+ ", actualRows=" + actualRows + "\n" + explanation);
				}
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void loadSparseData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			ThemeDataSetGenerator.generateSparse(
					ThemeDataSetGenerator.sparseConfig()
							.withPersonCount(120)
							.withOrganizationCount(12)
							.withDepartmentsPerOrganization(2)
							.withOffersPerDepartment(2)
							.withSparseCoveragePercent(20)
							.withReviewFanout(4)
							.withKnowsFanout(4)
							.withEmployeeFanout(4)
							.withEventFanout(4),
					new RDFInserter(connection));
			connection.commit();
		}
	}

	private static String sparsePrefixQuery(int prefixLength) {
		return PREFIX + "SELECT * WHERE {\n  "
				+ String.join("\n  ", SPARSE_DEEP_PATH_PREFIXES.subList(0, prefixLength))
				+ "\n}";
	}

	private static long countRows(SailRepositoryConnection connection, String query) {
		try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			long count = 0L;
			while (result.hasNext()) {
				result.next();
				count++;
			}
			return count;
		}
	}
}
